import sys, math

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T + 1):
        r = float(data[i])
        out.append(str(math.pi * r * r))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

